#!/usr/bin/env python3
"""Real two-node distributed forward pass: Mac (entry) + Rabbit R1 (exit).

This is the wire-level companion to `parity-station-handoff` (which proved the
same `forward_range_chunk(0..12)` then `(12..24)` split bit-perfect *in-process*).
Here the two halves run on two separate physical machines and the residual
genuinely crosses the USB wire between them:

    tokens -> /embed (Mac entry) -> /forward 0-12 (Mac entry)
           -> [residual over USB] ->
           -> /forward 12-24 (R1 exit) -> /lm-head (R1 exit) -> argmax

Both stations load the FULL qwen-0.5b knot; each runs only the layer range named
in the `X-Layer-Range` header (entry = 0-12 on the Mac, exit = 12-24 on the R1).
This distributes the *compute* across two real nodes using the exact kernel path
the golden star already validated. (Per-node *memory* sharding — so a model too
big for one node fits across several — is a separate, still-open path; see
R1_GOLDEN_STAR.md "Remaining".)

Setup:
  # Mac (native build):
  fat-station --knot ~/.edgework/models/qwen2.5-0.5b-instruct.knot \
              --role entry --layers 0..24 --port 8080
  # R1 (aarch64-musl build pushed to /data/local/tmp):
  adb shell 'cd /data/local/tmp && nohup ./fat-station --knot qwen05-dense.knot \
              --role exit --layers 12..24 --port 8090 > exit.log 2>&1 &'
  adb forward tcp:8090 tcp:8090
  python3 two-node-forward.py
"""
import urllib.request, struct, sys, time

MAC = "http://127.0.0.1:8080"   # Mac entry station (native)
R1  = "http://127.0.0.1:8090"   # adb-forwarded to the R1 exit station
TOKENS = [785, 6722, 315, 9625, 374]   # "The capital of France is" (Qwen)
EXPECT = 12095                          # " Paris"
SPLIT, TOTAL = 12, 24                   # entry 0..12 (Mac), exit 12..24 (R1)

def post(base, path, body, headers):
    req = urllib.request.Request(base + path, data=body, method="POST")
    for k, v in headers.items():
        req.add_header(k, v)
    with urllib.request.urlopen(req, timeout=300) as r:
        return r.read()

to_f32 = lambda b: list(struct.unpack("<%df" % (len(b) // 4), b))
u32b   = lambda a: struct.pack("<%dI" % len(a), *a)

seq = len(TOKENS)
t0 = time.time()
emb = post(MAC, "/embed", u32b(TOKENS), {"X-Position": "0"})
hidden = (len(emb) // 4) // seq
print(f"[mac]  /embed         -> {len(emb)//4} f32  (seq={seq} hidden={hidden})")
res1 = post(MAC, "/forward", emb,
            {"X-Position": "0", "X-Sequence-Length": str(seq), "X-Layer-Range": f"0-{SPLIT}"})
print(f"[mac]  /forward 0-{SPLIT}    -> {len(res1)//4} f32")
res2 = post(R1, "/forward", res1,
            {"X-Position": "0", "X-Sequence-Length": str(seq), "X-Layer-Range": f"{SPLIT}-{TOTAL}"})
print(f"[r1]   /forward {SPLIT}-{TOTAL}  -> {len(res2)//4} f32   (over the USB wire)")
logits = to_f32(post(R1, "/lm-head", res2, {"X-Sequence-Length": str(seq)}))
argmax = max(range(len(logits)), key=lambda i: logits[i])
dt = (time.time() - t0) * 1000
print(f"[r1]   /lm-head       -> vocab={len(logits)}")
print(f"\nargmax={argmax} logit={logits[argmax]:.4f}  expect={EXPECT}  ({dt:.0f} ms)")
ok = argmax == EXPECT
print("RESULT:", "PASS - Mac+R1 two-node forward answers ' Paris'" if ok else f"FAIL (got {argmax})")
sys.exit(0 if ok else 1)
